def find_root() -> Path:
    for cand in [Path.cwd(), *Path(__file__).resolve().parents]:
        if (cand / "backend" / "services" / "position_manager.py").exists():
            return cand
    print("FATAL: run from repo root")
    sys.exit(1)


def apply_all(root: Path) -> int:
    applied = 0
    for rel, old, new in CHUNKS:
        path = root / rel
        text = path.read_text()
        if new in text:
            print(f"[SKIP] {rel} — chunk already applied")
            continue
        n = text.count(old)
        if n != 1:
            print(f"[FAIL] {rel} — anchor found {n}x (expected 1). File drifted. ABORTING.")
            sys.exit(2)
        path.write_text(text.replace(old, new, 1))
        applied += 1
        print(f"[OK]   {rel} — chunk applied")
    for rel, content in NEW_FILES:
        path = root / rel
        if path.exists() and path.read_text() == content:
            print(f"[SKIP] {rel} — already present")
            continue
        path.parent.mkdir(parents=True, exist_ok=True)
        path.write_text(content)
        applied += 1
        print(f"[OK]   {rel} — written")
    return applied


def self_test(root: Path) -> None:
    print()
    print("── self-test: pytest ──")
    tests = [
        "tests/test_v332_regime_demotion.py",
        "tests/test_eod_naked_flatten_guard_v301.py",
        "tests/test_eod_force_flatten_bracketed_v302.py",
    ]
    existing = [t for t in tests if (root / "backend" / t).exists()]
    r = subprocess.run(
        [sys.executable, "-m", "pytest", "-q", *existing],
        cwd=str(root / "backend"), capture_output=True, text=True, timeout=300,
    )
    for line in (r.stdout or "").strip().splitlines()[-3:]:
        print("   " + line)
    if r.returncode != 0:
        print("[FAIL] self-test failed — see above. NOT safe to restart.")
        print((r.stdout or "")[-2000:])
        sys.exit(3)
    print("[OK]   self-test PASSED")


def main():
    root = find_root()
    print(f"repo root: {root}")
    applied = apply_all(root)
    self_test(root)
    print()
    print(f"v332 done — {applied} item(s) newly applied.")
    print("Next:")
    print("  git add -A && git commit -m 'v332: regime demotion + EOD style fix' && git push")
    print("  then RESTART the backend.")
    print()
    print("Monday after the close, run the EOD/pusher evidence probe:")
    print("  .venv/bin/python backend/scripts/diag_eod_pusher.py")
    print("and (live, 15:40-16:05 ET) backend/scripts/watch_pusher_eod.py —")
    print("paste both outputs for the 15:45 pusher-death verdict.")


if __name__ == "__main__":
    main()
